section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/php-eloquent.json",
  "type": "object",
  "required": ["laravel_version", "models", "prevent_lazy_loading_enabled", "paired_artefacts"],
  "properties": {
    "laravel_version": {"type": "string", "pattern": "^(10|11)\\."},
    "models": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": ["class", "uses_fillable", "uses_attribute_make", "uses_guarded_empty"],
        "properties": {
          "class": {"type": "string"},
          "uses_fillable": {"type": "boolean", "const": true},
          "uses_attribute_make": {"type": "boolean", "const": true},
          "uses_guarded_empty": {"type": "boolean", "const": false}
        }
      }
    },
    "prevent_lazy_loading_enabled": {"type": "boolean", "const": true},
    "paired_artefacts": {
      "type": "object",
      "required": ["migration", "factory", "resource"],
      "properties": {
        "migration": {"type": "boolean", "const": true},
        "factory": {"type": "boolean", "const": true},
        "resource": {"type": "boolean", "const": true}
      }
    },
    "forbidden_patterns_found": {"type": "array", "items": {"type": "string"}, "maxItems": 0}
  }
}
